const fs = require('fs');
const data = fs.readFileSync(0, 'utf8').trim().split(/\s+/).filter(s => s.length > 0);
let results = [];
for (let i = 0; i < data.length; i++) {
    const n = Number(data[i]);
    const ans = (n * n) / 2;
    results.push(String(ans));
}
if (results.length > 0) console.log(results.join('\n'));
